<?php
 namespace WPAICG\ContentWriter\TemplateManagerMethods; use WP_Error; if (!defined('ABSPATH')) { exit; } function delete_template_logic(\WPAICG\ContentWriter\AIPKit_Content_Writer_Template_Manager $managerInstance, int $template_id): bool|WP_Error { $wpdb = $managerInstance->get_wpdb(); $table_name = $managerInstance->get_table_name(); $user_id = get_current_user_id(); if (!$user_id) { return new WP_Error('not_logged_in', __('User must be logged in to delete templates.', 'gpt3-ai-content-generator')); } $where = ['id' => $template_id]; $where_formats = ['%d']; if (!\WPAICG\AIPKit_Role_Manager::user_can_manage_others_content()) { $where['user_id'] = $user_id; $where_formats[] = '%d'; } $result = $wpdb->delete($table_name, $where, $where_formats); if ($result === false) { return new WP_Error('db_delete_error', __('Failed to delete template from the database.', 'gpt3-ai-content-generator')); } if ($result === 0) { return new WP_Error('delete_permission_denied', __('Template not found or you do not have permission to delete it.', 'gpt3-ai-content-generator')); } return true; } 